from datetime import datetime, timedelta

def freshness_filter(bing_results):
    cutoff_date = datetime.now() - timedelta(days=90)
    fresh_results = []

    for result in bing_results:
        if 'freshness' in result and result['freshness'] > cutoff_date:
            fresh_results.append(result)
        elif is_time_sensitive_content(result):
            continue  # Skip stale time-sensitive content

    return fresh_results

def is_time_sensitive_content(result):
    time_keywords = ['election', 'market', 'stock', 'president', 'breaking']
    return any(keyword in result['title'].lower() for keyword in time_keywords)

